import{_ as t,H as e,f as r,i as l}from"./chunks/framework.eFU6Tutu.js";const p=JSON.parse('{"title":"Мята","description":"","frontmatter":{},"headers":[],"relativePath":"plants/mint.md","filePath":"plants/mint.md"}'),i={name:"plants/mint.md"};function n(h,a,o,d,s,u){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="мята" tabindex="-1">Мята <a class="header-anchor" href="#мята" aria-label="Permalink to &quot;Мята&quot;">​</a></h1><p>Мята - ароматное растение, которое легко вырастить на подоконнике. Её листья можно добавлять в чай, коктейли, салаты и десерты.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Растения этого рода достигают высоты 30—120 см. Габитус варьируется от травянистых однолетников (редко) или многолетников до полукустарников или кустарников. Эти растения обычно опушены простыми и прямыми волосками, а также железистыми волосками. Присутствуют ароматические вещества (эфирные масла), содержащиеся внутри железистых волосков. Все растения сильно ароматичны, с типичным острым и пикантным вкусом, но с чётко определёнными оттенками, которые могут различаться даже между популяциями.</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Сорт</th><th>Особенности</th></tr></thead><tbody><tr><td><strong>Мята перечная</strong></td><td>Самая популярная, острый вкус, много ментола</td></tr><tr><td><strong>Мята кудрявая</strong></td><td>Более мягкий вкус, красивые листья</td></tr><tr><td><strong>Мята яблочная</strong></td><td>Сладковатый аромат, хороша для десертов</td></tr><tr><td><strong>Мята шоколадная</strong></td><td>Лёгкий шоколадный оттенок, растёт медленнее</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Подробнее об уходе за укропом и другой зеленью читайте в <a href="/care/greens/#мята">гайде по уходу за зеленью</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><p><a href="/recipes/mint.html">Рецепты с использованием мяты</a></p><ul><li>Чай со свежей мятой</li><li>Мохито</li><li>Мятный соус к ягнёнку</li><li>Украшение десертов</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Успокаивает нервную систему</li><li>Помогает при расстройстве желудка</li><li>Освежает дыхание</li><li>Содержит витамины А и С</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://ru.ruwiki.ru/wiki/%D0%9C%D1%8F%D1%82%D0%B0" title="Статья о мяте" target="_blank" rel="noreferrer">РуВики</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/basil.html">Базилик</a></li><li><a href="/plants/chives.html">Зелёный лук</a></li><li><a href="/plants/parsley.html">Петрушка</a></li></ul>',17)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
